  const meta = (up as { _meta?: Record<string, unknown> })._meta;
  const usage =
    (meta?.usage as Record<string, unknown> | undefined) ??
    ((up as { usage?: Record<string, unknown> }).usage);
  if (usage && typeof usage === "object") {
    session.usage = usage;
  }
  switch (up.sessionUpdate) {
    case "agent_message_chunk":
    case "agent_thought_chunk": {
      const content = up.content as { type?: string; text?: string } | undefined;
      if (content?.type === "text" && typeof content.text === "string") {
        // Orphan turn: a message chunk arrived with no prompt turn in-flight
        // (typically a background sub-agent completion re-invoking the agent
        // via task-notification). The normal request→response flush path in
        // runPrompt isn't listening, so route it to the debounced orphan
        // flusher instead of the live-turn buffer. Thought chunks are never
        // user-facing, so only real message chunks take this path.
        if (up.sessionUpdate === "agent_message_chunk" && !session.inflight) {
          this.appendOrphan(session, content.text);
          break;
        }
        const wasEmpty = session.buffer.length === 0 && !session.thinkingBuffer;
        if (up.sessionUpdate === "agent_thought_chunk") {
          session.thinkingBuffer = (session.thinkingBuffer || "") + content.text;
        } else {
          session.buffer += content.text;
          session.charsOut += content.text.length;
        }
        if (wasEmpty) petState("streaming");
        // Early-capture RELAY_DELEGATE tokens during streaming.
        // Workaround: Kiro CLI may strip <<...>> from final text in pure-text turns,
        // but streaming chunks arrive unfiltered. We capture complete tokens here
        // so the final-render path can fall back to them if normal extraction finds nothing.
        // Inline/fenced code examples must stay inert, matching final token extraction.
        const captured = captureRelayDelegateTokensFromText(session.buffer, session._streamingDelegates ?? []);
        session._streamingDelegates = captured.length ? captured : undefined;
        session.onUpdate?.(session);
      }
      break;
    }
    case "tool_call": {
      const title = (up.title as string) ?? "tool";
      const startId = up.toolCallId as string | undefined;
      if (startId) (session._toolTitles ??= new Map()).set(startId, title);
      session.toolTimeline.push({
        id: startId ?? `__auto_${session.toolTimeline.length}`,
        name: title,
        status: "running",
        startedAt: Date.now(),
      });
      // Tier A precedingTools 唯一 push 維護點（避免 tool_call+update 兩處重複計數）。
      session._recentToolNames = appendToolName(session._recentToolNames ?? [], title);
      session._toolInFlight = true;
      petState("tool", title);
      session.onUpdate?.(session);
      break;
    }
    case "tool_call_update": {
      const status = up.status as string | undefined;
      const updId = up.toolCallId as string | undefined;
      // Adapter 可能在 tool_call 起始時只給殘缺 title（參數還在 stream），
      // 完整 title 之後才隨 update 補上——收到就回寫 timeline entry 與
      // _toolTitles，讓進度行和 log 都拿到完整工具名。
      const updTitle = typeof up.title === "string" && up.title ? up.title : undefined;
      let titleChanged = false;
      if (updTitle) {
        if (updId) (session._toolTitles ??= new Map()).set(updId, updTitle);
        let entry = updId
          ? session.toolTimeline.find((t) => t.id === updId)
          : undefined;
        if (!entry) {
          for (let i = session.toolTimeline.length - 1; i >= 0; i--) {
            if (session.toolTimeline[i].status === "running") {
              entry = session.toolTimeline[i];
              break;
            }
          }
        }
        if (entry && entry.name !== updTitle) {
          entry.name = updTitle;
          titleChanged = true;
        }
      }
      // Kiro 的 tool_call_update 只帶 opaque toolCallId、不帶 name。用綁定的
      // title 解析工具名；退而用 inline title，再退用 "tool"。
      const toolName =
        (updId ? session._toolTitles?.get(updId) : undefined) ??
        updTitle ??
        "tool";
      if (status === "completed") {
        markToolDone(session, updId, "completed");
        // A success clears any stale reflexion hint (fail streak is over).
        if (session.toolLog.length) session.toolLog = [];
        session._toolInFlight = false;
        session._consecutiveToolFails = 0;
        logEvent("tool_call", { name: toolName, status: "completed" }, { chatId: session.chatId });
        // Tier A seq observation：僅 ACP 路徑（Direct 由 tool-loop 的 Tier B rich 接手，避免雙記 BC-1）。
        // slice(0,-1) 排除「當前工具自身」（tool_call 已先 push title），對齊 rich 的「preceding 不含本 tool」語意。
        if (session.activeProvider === "acp") {
          recordSeqObservation({
            name: toolName,
            status: "completed",
            sessionId: session.sessionId,
            chatId: session.chatId,
            precedingTools: (session._recentToolNames ?? []).slice(0, -1),
          });
        }
        if (updId) session._toolTitles?.delete(updId);
        session.onUpdate?.(session);
      } else if (status === "failed") {
        markToolDone(session, updId, "failed");
        session._toolInFlight = false;
        session._consecutiveToolFails++;
        logEvent("tool_call", { name: toolName, status: "failed" }, { chatId: session.chatId });
        // Tier A seq observation：僅 ACP 路徑（Direct 失敗 tool 由 tool-loop catch 分支寫 rich）。
        if (session.activeProvider === "acp") {
          recordSeqObservation({
            name: toolName,
            status: "failed",
            sessionId: session.sessionId,
            chatId: session.chatId,
            precedingTools: (session._recentToolNames ?? []).slice(0, -1),
          });
        }
        if (updId) session._toolTitles?.delete(updId);
        if (session._consecutiveToolFails >= 2) {
          session.toolLog.push(
            `⚠️ [Reflexion hint] ${session._consecutiveToolFails} consecutive tool failures. ` +
            `STOP and diagnose: what assumption is wrong? Try a different approach.`
          );
        }
        session.onUpdate?.(session);
      } else if (titleChanged) {
        // in_progress 等中間更新：title 已回寫，刷新進度行顯示。
        // onUpdate 下游有 coalescing latch + 節流，高頻呼叫安全。
        session.onUpdate?.(session);
      }
      break;
    }
    default:
      // Ignore plan/user_message_chunk/etc. for the bridge.
      break;
  }
}

/**
 * Buffer an orphan-turn message chunk and (re)arm the quiescence timer.
 * Each new chunk pushes the flush out by orphanFlushQuiescenceMs so a

      "\n\n[⚠️ Context Budget Warning: session context has reached ~70% capacity. " +
      "Consider wrapping up the current task, using remember() to save important state, " +
      "and preparing for a <<RESTART:context budget>> if needed. " +
      "Avoid starting new multi-step tasks.]\n\n";
    console.log(`[budget] chat ${chatId} hit 70% context (${estimatedTokens}/${config.contextWindowTokens} tok)`);
  }
}

let promptText = text;
if (!session.preambleInjected && session.memoryPreamble) {
  promptText = session.memoryPreamble + text;
  session.preambleInjected = true;
}
if (budgetWarning) {
  promptText = budgetWarning + promptText;
}

const replyToId = ctx.message?.message_id;
const placeholderText = continuationContext
  ? `↻ Continuing (${continuationContext.turnIndex}/${continuationContext.maxTurns}) toward goal…`
  : replyHeader
    ? `${replyHeader}\n\nThinking…`
    : "Thinking…";
let placeholder: { message_id: number } | undefined;
// Draft streaming：private chat + 設定開啟時用 sendMessageDraft 取代 placeholder
const isPrivateChat = ctx.chat?.type === "private";
let useDraftMode = false;
let draftId = 0;
if (!isRelay && !isSilentMeta) {
  if (config.tgDraftEnabled && isPrivateChat) {
    draftId = Date.now() & 0x7FFFFFFF; // 正整數，非零
    const draftOk = await trySendDraft(ctx.api, chatId, draftId, "", false);
    if (draftOk) {
      useDraftMode = true;
    }
  }
  // Draft 失敗或不適用 → 走現有 placeholder
  if (!useDraftMode) {
    try {
      placeholder = await ctx.reply(placeholderText, {
        ...(replyToId ? { reply_parameters: { message_id: replyToId } } : {}),
      });
    } catch (err: any) {
      const desc = err?.description || err?.error?.description || "";
      if (replyToId && /message to be replied not found/i.test(desc)) {
        placeholder = await ctx.reply(placeholderText);
      } else {
        throw err;
      }
    }
  }
}

// Store placeholder msgId for optimistic cancel UI feedback
session._placeholderMsgId = placeholder?.message_id;

let lastEditAt = 0;
let lastRendered = "";
let lastDraftSentAt = Date.now();
let editTimer: NodeJS.Timeout | null = null;
let throttledSnapshotLogged = false;
let turnHitRateLimit = false;
let turnFinalized = false;

const editNowInner = async () => {
  if (!placeholder && !useDraftMode) return;
  if (rateLimitedUntil() > Date.now()) {
    turnHitRateLimit = true;
    if (!throttledSnapshotLogged) {
      throttledSnapshotLogged = true;
      const snapshot = (session.buffer || "").trim();
      const preview = snapshot.length > 800
        ? snapshot.slice(0, 800) + `…[+${snapshot.length - 800} chars]`
        : snapshot;
      console.warn(
        `[rate-limit] chat ${chatId} streaming paused; current buffer (${snapshot.length} chars):\n---\n${preview || "(empty)"}\n---`
      );
    }
    return;
  }
  // Draft path：全量替換 draft 內容。
  // 用 draft 專用 render（markdown 原文、volatile 區在 body 後）：
  // client 動畫以長度差淡入尾端字元，頭部插入會讓 body 尾端視覺倒退。
  if (useDraftMode && draftId) {
    const draftContent = renderDraftReply(session, scheduleParsers, replyHeader);
    if (draftContent === lastRendered) return;
    // 空內容走 plain（同初始 draft）：text=undefined → server 原生 "Thinking…"
    const ok = await trySendDraft(ctx.api, chatId, draftId, draftContent,
      draftContent ? config.tgRichStreamEnabled : false);
    if (ok) {
      lastRendered = draftContent;
      lastEditAt = Date.now();
      lastDraftSentAt = Date.now();
      return;
    }
    // Draft TTL 過期或 API 拒絕 → 降級為 placeholder 模式。
    // turn 已 finalize 就放棄降級：final render 自己會送，這裡再建
    // placeholder 只會多冒一則 streaming 幀。
    if (turnFinalized) return;
    if (!placeholder) {
      const { content, parseMode } = renderReply(session, false, scheduleParsers, replyHeader);
      try {
        placeholder = await ctx.api.sendMessage(chatId, content,
          parseMode ? { parse_mode: parseMode } : {});
        // placeholder 建立成功 → 正式降級
        useDraftMode = false;
        draftId = 0;
        lastRendered = content;
        lastEditAt = Date.now();
      } catch {
        // 降級也失敗（仍在 rate limit）→ 用新 draftId 下次重試，不進死狀態；
        // 不記錄 lastRendered，讓同內容下一 tick 仍會重試
        draftId = Date.now() & 0x7FFFFFFF;
      }
      return;
    }
    // 已有 placeholder → 降級，由下方 placeholder edit 接手；
    // 清空 lastRendered，避免 draft markdown 殘值干擾 identical check
    useDraftMode = false;
    draftId = 0;
    lastRendered = "";
  }
  if (turnFinalized) return;
  const { content, parseMode } = renderReply(session, false, scheduleParsers, replyHeader);
  if (content === lastRendered) return;
  lastRendered = content;
  lastEditAt = Date.now();
  try {
    if (placeholder) {
      if (config.tgRichStreamEnabled) {
        const richEdited = await tryEditRichMessageDraft(ctx.api, chatId, placeholder.message_id, content);
        if (richEdited) return;
      }
      await ctx.api.editMessageText(chatId, placeholder.message_id, content,
        parseMode ? { parse_mode: parseMode } : {});
    }
  } catch {
    // Telegram returns 400 if content identical; ignore.
  }
};

// 並發互斥：onUpdate（每 chunk）/ keepalive / recovery 多路觸發 editNow，
// 而 lastEditAt 只在成功後更新——送出失敗期間時間閘門全開，並發呼叫會在
// 「trySendDraft 失敗 → !placeholder → sendMessage」降級分支各自建立
// placeholder（2026-07-11 roadmap 事故：1x 則相同訊息）。coalesce 讓同一
// 時間最多一個 in-flight，中間的觸發合併成結束後補跑一次。
const editNow = coalesceAsyncRunner(editNowInner, () => turnFinalized);

// Draft keepalive：draft 是 ~30s TTL ephemeral，且「chat 收到任何一般訊息」
// 也會立即清掉。長 tool 執行無輸出、rate limit 早退、內容不變早退時都不會
// 刷新 → draft 過期，使用者看到訊息消失、下一幀才重現。每 10s 檢查，距上次
// 成功送出 ≥10s 就強制同 draftId 重送最新內容續命（最壞間隔 20s < 30s TTL）。
const DRAFT_KEEPALIVE_MS = 10_000;
const draftKeepalive: NodeJS.Timeout | null = useDraftMode
  ? setInterval(() => {
      if (turnFinalized || !useDraftMode || !draftId) return;
      if (rateLimitedUntil() > Date.now()) return;
      if (Date.now() - lastDraftSentAt < DRAFT_KEEPALIVE_MS) return;
      // sentinel 繞過 identical check 強制重送（"" 不行：全空 render 也是 ""，
      // "Thinking…" 階段的 keepalive 會被 identical check 吃掉）

