146	/**
147	 * Lines shown as the tool-progress prefix of the streamed reply: one line per
148	 * tool (latest 5) as `<emoji> <name> (<secs>s)`, followed by any advisory
149	 * lines (reflexion hints) carried in {@link ChatSession.toolLog}.
150	 */
151	// Tool 行是進度指示器不是審計記錄：title 是 adapter 原文（可能是整條
152	// Bash 命令或絕對路徑，甚至含換行），顯示層只取第一個詞（工具種類，
153	// 如 Find / Read / ls）+ 秒數，參數不進顯示；toolTimeline 保留原始
154	// 資料供 log / 診斷。第一個詞仍可能是無空白長路徑，故保留截斷上限。
155	const TOOL_KIND_MAX = 24;
156	
157	export function toolPrefixLines(session: ChatSession): string[] {
158	  const lines = session.toolTimeline.slice(-5).map((t) => {
159	    const secs =
160	      t.status !== "running" && t.elapsedMs !== undefined
161	        ? ` (${(t.elapsedMs / 1000).toFixed(1)}s)`
162	        : "";
163	    let name = t.name.replace(/\s*[\r\n]+\s*/g, " ").trim().split(" ")[0] || "tool";
164	    if (name.length > TOOL_KIND_MAX) {
165	      name = name.slice(0, TOOL_KIND_MAX - 1) + "…";
166	    }
167	    return `${TOOL_STATUS_EMOJI[t.status]} ${name}${secs}`;
168	  });
169	  return [...lines, ...session.toolLog];
170	}
